        if (schemaContent == null || schemaContent.trim().isEmpty()) {
            return false;
        }

        try {
            // Use the secure processing feature to prevent XXE attacks
            SchemaFactory factory = SchemaFactory.newInstance(XMLConstants.W3C_XML_SCHEMA_NS_URI);

            // Configure secure processing
            factory.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);

            // Explicitly disallow external DTDs and schemas to prevent external entity expansion
            try {
                factory.setProperty(XMLConstants.ACCESS_EXTERNAL_DTD, "");
                factory.setProperty(XMLConstants.ACCESS_EXTERNAL_SCHEMA, "");
            } catch (IllegalArgumentException e) {
                // Property might not be supported on all implementations, 
                // but FEATURE_SECURE_PROCESSING provides baseline protection.
            }

            // Parse the schema content
            // We use a StreamSource wrapping a StringReader to avoid creating temporary files
            StreamSource source = new StreamSource(new StringReader(schemaContent));

            // Attempt to create the schema. This triggers the parsing and validation of the XSD itself.
            Schema schema = factory.newSchema(source);

            // If the schema object is successfully created, the XSD is valid.
            return schema != null;

        } catch (Exception e) {
            // Catching specific exceptions (SAXException, IOException) and general Exception
            // to ensure robustness. Any parsing error or structural invalidity in the XSD
            // will result in an exception, indicating invalidity.
            return false;
        }
    }
